import React, { useState } from "react";
import { useUser } from "./contexts/UserContext";
import { useNavigate } from "react-router-dom";

export default function Login() {
  const [username, setUsername] = useState("");
  const [senha, setSenha] = useState("");
  const { setUser } = useUser();
  const navigate = useNavigate();

  function handleLogin(e) {
    e.preventDefault();
    // Mock login: se digitar admin, vira admin, senão aluno
    const tipo = username.trim().toLowerCase() === "admin" ? "admin" : "aluno";
    setUser({ nome: username, tipo });
    navigate("/dashboard");
  }

  return (
    <div className="min-h-screen bg-[#f4f7fa] flex items-center justify-center">
      <div className="flex w-full max-w-4xl rounded-3xl bg-white shadow-lg overflow-hidden">
        <div className="flex-1 hidden md:flex items-center justify-center bg-[#eaf2fa]">
          {/* Pode substituir por sua logo/arte */}
          <img src="/logo.png" alt="Logo" className="max-w-[360px] mx-auto" />
        </div>
        <form className="flex-1 p-10 flex flex-col justify-center" onSubmit={handleLogin}>
          <h2 className="text-2xl font-bold mb-6 text-[#1d3557] text-center">PoliUB Atendimento</h2>
          <input
            placeholder="Nome"
            className="mb-4 p-3 rounded-xl border focus:outline-none focus:ring-2 focus:ring-[#3172C0]"
            value={username}
            onChange={e => setUsername(e.target.value)}
            required
          />
          <input
            placeholder="Senha"
            type="password"
            className="mb-6 p-3 rounded-xl border focus:outline-none focus:ring-2 focus:ring-[#3172C0]"
            value={senha}
            onChange={e => setSenha(e.target.value)}
            required
          />
          <button
            className="w-full bg-[#3172C0] text-white py-3 rounded-full font-semibold hover:bg-[#083A76] transition"
            type="submit"
          >
            Entrar
          </button>
        </form>
      </div>
    </div>
  );
}
